[
    {
        "role": "paragraph",
        "segment": "One size measure in object-oriented (OO) systems is counting objects and methods as a basic size measure.",
        "citations": [
            {
                "type": "source_text",
                "content": "Pfleeger (1991) used objects and methods as a basic size measure in her effort-estimation approach",
                "img_id": null
            }
        ]
    },
    {
        "role": "sentence",
        "segment": "The advantage of this measure is that it uses the same or similar language throughout each stage of the life cycle, making it convenient to measure size in the same terms from a system's inception to its delivery and maintenance.",
        "citations": [
            {
                "type": "source_text",
                "content": "unlike other paradigms, with an OO approach, we use the same or similar language throughout each stage of the life cycle, making it convenient to measure size in the same terms from a system's inception to its delivery and maintenance.",
                "img_id": null
            }
        ]
    },
    {
        "role": "sentence",
        "segment": "This allows the estimation technique to be reapplied during development, and the estimate inputs are directly comparable.",
        "citations": [
