[
    {
        "role": "paragraph",
        "segment": "Training aids and documentation need to be tailored to different user groups because novice and expert users have different needs and levels of familiarity with the system.",
        "citations": [
            {
                "type": "source_text",
                "content": "Sometimes, the same person is both user and operator. However, user and operator tasks have very different goals, so the training for each job emphasizes different aspects of the system.",
                "img_id": null
