[
    {
        "role": "paragraph",
        "segment": "The severity information collected from failure reports can help the Software Engineering Laboratory (SEL) understand the impact of defects on the maintenance process by categorizing defects into major defects with no workaround, major defects with a workaround, and cosmetic defects.",
        "citations": [
            {
                "type": "source_text",
                "content": "When users fill out failure reports, they are asked to indicate the severity of the defect according to the following scale: major defect with no workaround; major defect, but workaround exists; cosmetic defect.",
